const files = $('Aggregate files').first().json.files;
const sheetRows = $input.all().map(item => item.json);
const existingIds = new Set(
  sheetRows.map(r => r.receipt_id).filter(id => !!id)
);
const force = !!$('On form submission').first().json['Force reprocess'];
const toProcess = force ? files : files.filter(f => !existingIds.has(f.id));
const BLOCKED_EXT = new Set(['.docx', '.doc', '.xlsx', '.xls', '.pptx', '.ppt', '.txt', '.csv', '.zip', '.mp4', '.mov', '.mp3']);
const filteredToProcess = toProcess.filter(f => {
  if (f.mimeType?.startsWith('application/vnd.google-apps.')) return false;
  const ext = (f.name || '').toLowerCase().match(/\.[^.]+$/)?.[0];
  // No extension: let through — may be a PDF/image saved without extension; Stop and Error will catch it
  if (!ext) return true;
  return !BLOCKED_EXT.has(ext);
});
return filteredToProcess.map(f => ({ json: f }));

const llmItems = $input.all();
const srcItems = $('Has resize output? (PDF)').all();
return llmItems.map((item, i) => {
  const text = item.json?.text || '';
  const ridMatch = text.match(/"receipt_id"\s*:\s*"([^"]+)"/);
  const receiptId = ridMatch ? ridMatch[1] : (srcItems[i]?.json?.id || '');
  const filename = srcItems[i]?.json?.name || '';
  return { json: { ...item.json, receipt_id: receiptId, filename: filename } };
});

const item = $input.item;
const text = item.json.text || '';
const cleaned = text.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  throw new Error('JSON parse failed: ' + e.message);
}
// Normalize: items field name variations
if (parsed && !parsed.items) {
  parsed.items = parsed.individual_items || parsed.line_items || parsed.products || parsed.purchased_items || [];
}
if (!parsed?.receipt_info || !Array.isArray(parsed?.items)) {
  throw new Error('Schema mismatch: missing receipt_info or items');
}
// Normalize: confidence may be at top level instead of inside receipt_info
const ri = parsed.receipt_info;
if (ri.confidence == null) {
  ri.confidence = ri.confidence_score ?? parsed.confidence ?? parsed.confidence_score ?? 3;
}
// Normalize: store field name variations
ri.store = ri.store || ri.store_name || ri.merchant || ri.vendor || ri.retailer || '';
// Normalize: date field name variations + format (YYYY-MM-DD or DD.MM.YYYY)
const rawDate = ri.date || ri.receipt_date || ri.transaction_date || ri.purchase_date || '';
const isoMatch = rawDate.match(/^(\d{4})-(\d{2})-(\d{2})/);
const deMatch  = rawDate.match(/^(\d{2})\.(\d{2})\.(\d{4})$/);
ri.date = isoMatch ? `${isoMatch[1]}-${isoMatch[2]}-${isoMatch[3]}`
        : deMatch  ? `${deMatch[3]}-${deMatch[2]}-${deMatch[1]}`
        : '';
// Default numeric fields to avoid NaN in downstream Set nodes
ri.tax_amount = ri.tax_amount ?? 0;
ri.subtotal = ri.subtotal ?? 0;
ri.deposits = ri.deposits ?? 0;
ri.discounts = ri.discounts ?? 0;
// Normalize items: quantity 0/null/undefined → 1
// quantity: 0/null/fraction(<1) → 1; weight-based items use fraction as qty
parsed.items = parsed.items.map(it => {
  const qty = Number(it.quantity);
  return { ...it, quantity: (Number.isFinite(qty) && qty >= 1) ? qty : 1 };
});
const receiptId = parsed.receipt_id || item.json.receipt_id || '';
delete parsed.receipt_id;
return { json: { output: parsed, text: text, receipt_id: receiptId, filename: item.json.filename } };

